tool_args.new_str:
int MCE_handle_MBMS_SESSION_START_REQUEST(instance_t instance,
                                        uint32_t assoc_id,
                                        uint32_t stream,
                                        M3AP_M3AP_PDU_t *pdu){
  LOG_D(M3AP, "MCE_handle_MBMS_SESSION_START_REQUEST assoc_id %d\n",assoc_id);

  MessageDef                         *message_p;
  M3AP_MBMSSessionStartRequest_t              *container;
  M3AP_MBMSSessionStartRequest_IEs_t        *ie;
  int i = 0;

  DevAssert(pdu != NULL);

  container = &pdu->choice.initiatingMessage.value.choice.MBMSSessionStartRequest;

  message_p = itti_alloc_new_message(TASK_M3AP_MCE, 0, M3AP_MBMS_SESSION_START_REQ);

  /* Extract mandatory fields from the request */
  for (i = 0; i < container->protocolIEs.list.count; i++) {
    ie = container->protocolIEs.list.array[i];
    switch (ie->id) {
      case M3AP_ProtocolIE_ID_id_MME_MBMS_M3AP_ID:
        M3AP_MBMS_SESSION_START_REQ(message_p).mme_mbms_m3ap_id = ie->value.choice.MME_MBMS_M3AP_ID;
        LOG_D(M3AP, "MBMS Session Start Request: MME_MBMS_M3AP_ID %lu\n", 
              M3AP_MBMS_SESSION_START_REQ(message_p).mme_mbms_m3ap_id);
        break;

      case M3AP_ProtocolIE_ID_id_TMGI:
        if (ie->value.choice.TMGI.size == 6) { // TMGI is 6 bytes
          memcpy(&M3AP_MBMS_SESSION_START_REQ(message_p).tmgi, 
                 ie->value.choice.TMGI.buf, 
                 ie->value.choice.TMGI.size);
          LOG_D(M3AP, "MBMS Session Start Request: TMGI extracted\n");
        }
        break;

      case M3AP_ProtocolIE_ID_id_MBMS_Session_ID:
        if (ie->value.present == M3AP_MBMSSessionStartRequest_IEs__value_PR_MBMS_Session_ID) {
          M3AP_MBMS_SESSION_START_REQ(message_p).mbms_session_id = ie->value.choice.MBMS_Session_ID;
          LOG_D(M3AP, "MBMS Session Start Request: MBMS_Session_ID %ld\n", 
                M3AP_MBMS_SESSION_START_REQ(message_p).mbms_session_id);
        }
        break;

      case M3AP_ProtocolIE_ID_id_MBMS_Service_Area:
        if (ie->value.choice.MBMS_Service_Area.size >= 2) {
          memcpy(&M3AP_MBMS_SESSION_START_REQ(message_p).mbms_service_area, 
                 ie->value.choice.MBMS_Service_Area.buf, 
                 ie->value.choice.MBMS_Service_Area.size);
          M3AP_MBMS_SESSION_START_REQ(message_p).mbms_service_area_len = ie->value.choice.MBMS_Service_Area.size;
          LOG_D(M3AP, "MBMS Session Start Request: MBMS_Service_Area extracted (%d bytes)\n", 
                M3AP_MBMS_SESSION_START_REQ(message_p).mbms_service_area_len);
        }
        break;

      case M3AP_ProtocolIE_ID_id_MBMS_Cell_List:
        if (ie->value.present == M3AP_MBMSSessionStartRequest_IEs__value_PR_MBMS_Cell_List) {
          M3AP_MBMS_SESSION_START_REQ(message_p).mbms_cell_list = ie->value.choice.MBMS_Cell_List;
          LOG_D(M3AP, "MBMS Session Start Request: MBMS_Cell_List present\n");
        }
        break;
    }
  }

  /* M3 Setup Request == Non UE-related procedure -> stream 0 */
  if (stream != 0) {
    LOG_W(M3AP, "[SCTP %d] Received MBMS session start request on stream != 0 (%d)\n",
              assoc_id, stream);
  }

  itti_send_msg_to_task(TASK_MCE_APP, ENB_MODULE_ID_TO_INSTANCE(instance), message_p);

  return 0;
}
